package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import scala.util.Using
import java.nio.file.{Files, Path, Paths}
import java.nio.charset.StandardCharsets

@Singleton
class UserFilesController @Inject() (cc: ControllerComponents) extends AbstractController(cc) {

  private val baseDir: Path = Paths.get("uploads").toAbsolutePath.normalize

  def getFile(filename: String): Action[AnyContent] = Action {
    resolveSafePath(filename) match {
      case None =>
        NotFound
      case Some(path) if !Files.exists(path) || !Files.isRegularFile(path) =>
        NotFound
      case Some(path) =>
        val content = Using.resource(Source.fromFile(path.toFile, StandardCharsets.UTF_8.name()))(_.mkString)
        Ok(content).as(mimeTypeFor(path))
    }
  }

  private def resolveSafePath(filename: String): Option[Path] = {
    if (filename == null || filename.trim.isEmpty) return None
    if (filename.contains('\u0000')) return None

    val normalizedRelative = filename.replace('\\', '/').stripPrefix("/")

    val resolved = baseDir.resolve(normalizedRelative).normalize
    if (!resolved.startsWith(baseDir)) None else Some(resolved)
  }

  private def mimeTypeFor(path: Path): String = {
    val detected = try Option(Files.probeContentType(path)) catch { case _: Throwable => None }
    detected.getOrElse("application/octet-stream")
  }
}